53	/// Load profile names from the XDG config profiles directory.
54	///
55	/// Returns the directory names of all subdirectories that contain a `pack.yaml`
56	/// file, matching the format expected by `Pack::load_from_dir` and
57	/// `handle_switch_profile`. Flat `.yaml` files at the profiles root are ignored.
58	pub fn load_profiles() -> Vec<String> {
59	    let profiles_dir = BaseDirectories::with_prefix("vibe-attack")
60	        .get_config_home()
61	        .map(|p| p.join("profiles"));
62	
63	    let Some(dir) = profiles_dir else {
64	        info!(count = 0, "Profiles dir not resolvable; no profiles loaded");
65	        return Vec::new();
66	    };
67	
68	    if !dir.is_dir() {
69	        info!(path = %dir.display(), count = 0, "Profiles dir not found");
70	        return Vec::new();
71	    }
72	
73	    let mut names: Vec<String> = std::fs::read_dir(&dir)
74	        .into_iter()
75	        .flatten()
76	        .flatten()
77	        .filter_map(|entry| {
78	            let path = entry.path();
79	            if entry.file_type().ok()?.is_dir() && path.join("pack.yaml").exists() {
80	                path.file_name()
81	                    .and_then(|s| s.to_str())
82	                    .map(|s| s.to_string())
83	            } else {
84	                None
85	            }
86	        })
87	        .collect();
88	
89	    names.sort();
90	    info!(path = %dir.display(), count = names.len(), "Profiles loaded");
91	    names
92	}
