203	fn handle_switch_profile(name: &str, handle: &DaemonHandle) -> Result<()> {
204	    use crate::pack::Pack;
205	    use crate::pack::manager::ProfileManager;
206	
207	    let dir = crate::pack::get_profiles_dir()?.join(name);
208	    let pack = Pack::load_from_dir(&dir)?;
209	    handle.dispatcher.update_macros(pack.flatten());
210	
211	    // Track active profile for status queries
212	    *handle.active_profile.write().unwrap() = Some(name.to_string());
213	
214	    // Update persistence so it survives restart
215	    let mut manager = ProfileManager::load().unwrap_or(ProfileManager { active_profile: None });
216	    manager.active_profile = Some(name.to_string());
217	    manager.save()?;
218	
219	    Ok(())
220	}
