222	// Server-side path resolution: uses place_runtime_file, which creates the XDG runtime
223	// directory if it doesn't exist yet. The read-only counterpart lives in control/client.rs.
224	fn get_socket_path() -> Result<PathBuf> {
225	    let xdg = xdg::BaseDirectories::with_prefix("vibe-attack");
226	
227	    xdg.place_runtime_file("vibe-attack.sock")
228	        .context("Failed to place UDS socket in runtime directory")
