31	/// Handle returned by [`TrayHandle::spawn`]; keeps the tray alive for the process lifetime.
32	pub struct TrayHandle {
33	    /// Set to true by the tray "Open Config" action; cleared by the eframe loop.
34	    pub open_window: Arc<AtomicBool>,
35	    _thread: std::thread::JoinHandle<()>,
36	}
