111	    let wake_preroll_frames: usize = WAKE_PREROLL_MS.div_ceil(20) as usize;
112	
113	    // Build VAD config from config file.
114	    let ms_to_frames = |ms: u64| ms.div_ceil(20).max(1) as usize;
